// Handle inbound WhatsApp commands. Only messages starting with "/" are acted
// on — the bot's own emoji-formatted nudges never start with "/", so no loops.
const fs = require('fs');
const path = require('path');
const INBOX = '/data/inbox';
const out = [];

for (const item of $input.all()) {
  const body = item.json.body || item.json;          // n8n webhook nests under .body
  const data = body.data || {};
  const msg = data.message || {};
  const text = String(msg.conversation || (msg.extendedTextMessage && msg.extendedTextMessage.text) || '').trim();
  const jid = (data.key && data.key.remoteJid) || '';
  const number = jid.replace(/@.*$/, '');
  if (!text || !number || !text.startsWith('/')) continue;   // ignore non-commands

  const m = text.match(/^\/(\w+)\s*([\s\S]*)$/);
  const cmd = (m ? m[1] : '').toLowerCase();
  const arg = m ? m[2].trim() : '';
  try { fs.mkdirSync(INBOX, { recursive: true }); } catch (e) {}

  let reply;
  if ((cmd === 'note' || cmd === 'n' || cmd === 'capture') && arg) {
    const ts = new Date();
    const slug = (arg.toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/^-+|-+$/g, '').slice(0, 40)) || 'note';
    const fname = `${ts.toISOString().slice(0, 10)}-${ts.getTime()}-${slug}.md`;
    const md = `---\ntype: capture\ncreated: ${ts.toISOString()}\nsource: whatsapp\n---\n\n${arg}\n`;
    fs.writeFileSync(path.join(INBOX, fname), md);
    reply = `📥 Captured to inbox as _${fname}_`;
  } else if ((cmd === 'done' || cmd === 'touch' || cmd === 'did' || cmd === 'reopen') && arg) {
    const action = cmd === 'done' ? 'done' : (cmd === 'reopen' ? 'reopen' : 'touch');
    fs.appendFileSync(path.join(INBOX, '.actions.jsonl'), JSON.stringify({ ts: new Date().toISOString(), action, project: arg }) + '\n');
    reply = action === 'done'
      ? `✅ Marked _${arg}_ as done — it won't nudge you again.`
      : `👍 Logged activity on _${arg}_ — staleness clock reset.`;
  } else if (cmd === 'help') {
    reply = '*Second Brain commands*\n📥 /note <text> — capture a thought\n👍 /touch <project> — reset its staleness clock\n✅ /done <project> — stop nudging it\n♻️ /reopen <project> — undo a done\n❓ /help — this message';
  } else {
    reply = '🤖 Unknown or empty command. Send */help* for the list.';
  }
  out.push({ json: { number, reply } });
}
return out;
